import { Constructor, LitElement } from 'lit-element';
import { ScopedElementsMixin } from '@open-wc/scoped-elements';
import { MobxReactionUpdate } from '@adobe/lit-mobx';
import { Dictionary } from '@holochain-open-dev/core-types';

export abstract class BaseElement<STORE> extends MobxReactionUpdate(
  ScopedElementsMixin(LitElement)
) {
  connectedCallback() {
    super.connectedCallback();
    for (const [tag, el] of Object.entries(this.getScopedElements())) {
      this.defineScopedElement(tag, el);
    }
  }

  abstract get store(): STORE;

  getScopedElements(): Dictionary<Constructor<HTMLElement>> {
    return {};
  }
}

type AbstractConstructor<T> = Function & { prototype: T };

export function connectStore<S, T extends AbstractConstructor<BaseElement<S>>>(
  baseClass: T,
  store: S
): Constructor<HTMLElement> {
  return class extends ((baseClass as unknown) as typeof HTMLElement) {
    get store(): S {
      return store;
    }
  };
}
